import React, { useState, useEffect, useRef } from 'react';
import { 
  Sparkles, 
  Package, 
  History,
  LayoutGrid,
  MapPin,
  GitCompare,
  CheckCircle2,
  Type,
  Square,
  AlertCircle,
  RefreshCw,
  Wand2,
  ChevronRight,
  Zap,
  Fingerprint,
  Crown,
  Trophy,
  Download,
  X,
  Plus,
  Trash2,
  List,
  RotateCcw,
  Check
} from 'lucide-react';
import { Button } from './components/Button';
import { FileUploader } from './components/FileUploader';
import { generateAsset, ImageCategory } from './services/geminiService';
import { GeneratedMockup, LoadingState } from './types';
import { useApiKey } from './hooks/useApiKey';
import ApiKeyDialog from './components/ApiKeyDialog';

interface ProductSpec {
  key: string;
  value: string;
}

const processImage = async (
  base64Str: string, 
  category: ImageCategory, 
  targetPx: number = 800, 
  maxSizeMB: number = 1
): Promise<string> => {
  return new Promise((resolve) => {
    const img = new Image();
    img.src = base64Str;
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = targetPx;
      canvas.height = targetPx;
      const ctx = canvas.getContext('2d');
      if (!ctx) return resolve(base64Str);

      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
      ctx.drawImage(img, 0, 0, targetPx, targetPx);

      if (category === 'main') {
        ctx.save();
        const watermarkText = "MURO";
        ctx.font = '300 15px "Inter", "sans-serif"';
        ctx.textAlign = 'left';
        ctx.textBaseline = 'top';
        ctx.letterSpacing = '4px';
        const xPos = 40;
        const yPos = 40;
        ctx.fillStyle = 'rgba(0, 0, 0, 0.12)'; 
        ctx.fillText(watermarkText, xPos, yPos);
        ctx.beginPath();
        const textWidth = ctx.measureText(watermarkText).width;
        ctx.arc(xPos + textWidth + 10, yPos + 8, 1.5, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(127, 0, 25, 0.15)'; 
        ctx.fill();
        ctx.restore();
      }

      if (category === 'lifestyle') {
        ctx.save();
        const text = '場景演示';
        ctx.font = '400 11px "Noto Sans TC", sans-serif';
        const metrics = ctx.measureText(text);
        const textWidth = metrics.width;
        const padding = 10;
        const rectWidth = textWidth + (padding * 2);
        const rectHeight = 22;
        const x = targetPx - rectWidth - 15;
        const y = targetPx - rectHeight - 15;
        ctx.fillStyle = 'rgba(255, 255, 255, 0.85)';
        ctx.fillRect(x, y, rectWidth, rectHeight);
        ctx.fillStyle = '#111';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(text, x + (rectWidth / 2), y + (rectHeight / 2));
        ctx.restore();
      }

      let quality = 0.92;
      let result = canvas.toDataURL('image/jpeg', quality);
      while (result.length > maxSizeMB * 1024 * 1024 * 1.33 && quality > 0.1) {
        quality -= 0.05;
        result = canvas.toDataURL('image/jpeg', quality);
      }
      resolve(result);
    };
  });
};

const IntroSequence = ({ onComplete }: { onComplete: () => void }) => {
  useEffect(() => {
    const timer = setTimeout(onComplete, 2500);
    return () => clearTimeout(timer);
  }, [onComplete]);

  return (
    <div className="fixed inset-0 z-[100] bg-white flex flex-col items-center justify-center animate-fade-in">
      <div className="flex flex-col items-center gap-6">
        <div className="w-16 h-16 border border-zinc-200 flex items-center justify-center rounded-sm">
          <Package size={32} className="text-[#7f0019]" strokeWidth={1.5} />
        </div>
        <div className="text-center">
          <h1 className="text-3xl font-light tracking-[0.4em] text-zinc-800">MURO AI</h1>
          <p className="text-xs text-zinc-400 mt-2 tracking-[0.2em] uppercase">Pro Studio Edition</p>
        </div>
      </div>
    </div>
  );
};

export default function App() {
  const [showIntro, setShowIntro] = useState(true);
  const [view, setView] = useState<'generate' | 'gallery'>('generate');
  const [selectedMockup, setSelectedMockup] = useState<GeneratedMockup | null>(null);
  const [zoomedImage, setZoomedImage] = useState<{url: string, title: string} | null>(null);

  const [productTitle, setProductTitle] = useState('');
  const [mainImageTitle, setMainImageTitle] = useState('');
  const [sceneDescription, setSceneDescription] = useState('');
  const [ownAdvantage, setOwnAdvantage] = useState('');
  const [marketDisadvantage, setMarketDisadvantage] = useState('');
  const [optimizationPrompt, setOptimizationPrompt] = useState('');

  const getInitialSpecs = (): ProductSpec[] => [
    { key: '材質', value: '' },
    { key: '規格', value: '' },
    { key: '重量', value: '' },
    { key: '顏色', value: '' }
  ];

  const [specs, setSpecs] = useState<ProductSpec[]>(getInitialSpecs());
  const [optLogs, setOptLogs] = useState<string[]>(["Pro 800px JPG 渲染引擎已鎖定。"]);
  const [mainUploadedPreviews, setMainUploadedPreviews] = useState<string[]>([]);
  const [detailUploadedPreviews, setDetailUploadedPreviews] = useState<string[]>([]);
  const [currentGeneration, setCurrentGeneration] = useState<(string | null)[]>(Array(12).fill(null));
  const [activeIndices, setActiveIndices] = useState<number[]>([]); 
  const [displayFilter, setDisplayFilter] = useState<ImageCategory | 'all' | null>(null); 
  const [gallery, setGallery] = useState<GeneratedMockup[]>([]);
  const [loading, setLoading] = useState<LoadingState>({ isGenerating: false, message: '' });

  // 新增：使用者勾選要生成的類別
  const [selectedCategories, setSelectedCategories] = useState<ImageCategory[]>(['main', 'comparison', 'lifestyle', 'detail']);

  const stopGenerationRef = useRef(false);
  const { showApiKeyDialog, validateApiKey, resetAndOpen, handleApiKeyDialogContinue } = useApiKey();

  const categoryConfigs: {type: ImageCategory; name: string; indices: number[]; icon: React.ReactNode}[] = [
    { type: 'main', name: '產品主圖', indices: [0, 1, 2], icon: <Sparkles size={16} /> },
    { type: 'comparison', name: '市場比較圖', indices: [3, 4, 5], icon: <GitCompare size={16} /> },
    { type: 'lifestyle', name: '場景演示圖', indices: [6, 7, 8], icon: <MapPin size={16} /> },
    { type: 'detail', name: '詳情圖', indices: [9, 10, 11], icon: <LayoutGrid size={16} /> }
  ];

  const addLog = (msg: string) => {
    setOptLogs(prev => [msg, ...prev].slice(0, 8));
  };

  const handleReset = () => {
    if (window.confirm("確定要清空工作台所有輸入內容嗎？")) {
      setProductTitle('');
      setMainImageTitle('');
      setSceneDescription('');
      setOwnAdvantage('');
      setMarketDisadvantage('');
      setOptimizationPrompt('');
      setSpecs(getInitialSpecs()); 
      setMainUploadedPreviews([]);
      setDetailUploadedPreviews([]);
      setCurrentGeneration(Array(12).fill(null));
      setActiveIndices([]);
      setDisplayFilter(null);
      setSelectedCategories(['main', 'comparison', 'lifestyle', 'detail']);
      setLoading({ isGenerating: false, message: '' });
      addLog("工作台已全部清除。");
    }
  };

  const handleAddSpec = () => {
    setSpecs([...specs, { key: '', value: '' }]);
  };

  const handleUpdateSpec = (index: number, field: 'key' | 'value', value: string) => {
    const newSpecs = [...specs];
    newSpecs[index][field] = value;
    setSpecs(newSpecs);
  };

  const handleRemoveSpec = (index: number) => {
    setSpecs(specs.filter((_, i) => i !== index));
  };

  const downloadImage = (url: string, filename: string) => {
    const link = document.createElement('a');
    link.href = url;
    link.download = `${filename || 'muro-design'}.jpg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleMainFilesSelect = async (files: File[]) => {
    const newItems = await Promise.all(files.map(async (file) => {
      const base64 = await new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
      return base64;
    }));
    setMainUploadedPreviews(prev => [...prev, ...newItems]);
    addLog(`載入：產品主圖素材已就位。`);
  };

  const handleDetailFilesSelect = async (files: File[]) => {
    const newItems = await Promise.all(files.map(async (file) => {
      const base64 = await new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
      return base64;
    }));
    setDetailUploadedPreviews(prev => [...prev, ...newItems]);
    addLog(`載入：詳情細節素材已就位。`);
  };

  const generateProcess = async (targetIndices: number[]) => {
    if (targetIndices.length === 0) return;

    for (const globalIndex of targetIndices) {
      if (stopGenerationRef.current) break;

      const config = categoryConfigs.find(c => c.indices.includes(globalIndex))!;
      const subIndex = config.indices.indexOf(globalIndex) + 1;

      setLoading(prev => ({ ...prev, message: `正在生成：${config.name} (${subIndex}/3)...` }));

      try {
        const rawB64 = await generateAsset(
          productTitle, 
          config.type, 
          mainUploadedPreviews, 
          sceneDescription, 
          ownAdvantage,
          marketDisadvantage,
          optimizationPrompt,
          mainImageTitle,
          specs,
          detailUploadedPreviews
        );

        const processedB64 = await processImage(rawB64, config.type, 800, 1);

        if (!stopGenerationRef.current) {
          setCurrentGeneration(prev => {
            const next = [...prev];
            next[globalIndex] = processedB64;
            return next;
          });
          setActiveIndices(prev => prev.filter(idx => idx !== globalIndex));
        }
      } catch (e: any) {
        console.error(`Index ${globalIndex} failed:`, e);
        const errStr = e.message || String(e);
        if (errStr.includes("429") || errStr.includes("RESOURCE_EXHAUSTED") || errStr.includes("quota")) {
          setLoading({ isGenerating: false, message: '配額不足，請更換 API 金鑰。' });
          addLog("系統錯誤：API 資源耗盡。");
          stopGenerationRef.current = true;
          resetAndOpen();
          break;
        }
        setActiveIndices(prev => prev.filter(idx => idx !== globalIndex));
      }
    }
  };

  const handleStartProduction = async () => {
    if (!productTitle.trim() && mainUploadedPreviews.length === 0) return;
    if (selectedCategories.length === 0) {
      addLog("請先選擇至少一種生成類型。");
      return;
    }
    if (!(await validateApiKey())) return;

    // 計算所有被選中類別的索引
    const allTargetIndices: number[] = [];
    categoryConfigs.forEach(config => {
      if (selectedCategories.includes(config.type)) {
        allTargetIndices.push(...config.indices);
      }
    });

    setDisplayFilter('all');
    setLoading({ isGenerating: true, message: '執行選定渲染任務...' });

    // 只清空被選取的索引內容
    setCurrentGeneration(prev => {
      const next = [...prev];
      allTargetIndices.forEach(idx => next[idx] = null);
      return next;
    });

    setActiveIndices(allTargetIndices);
    stopGenerationRef.current = false;

    const selectedNames = categoryConfigs
      .filter(c => selectedCategories.includes(c.type))
      .map(c => c.name)
      .join(', ');

    addLog(`啟動任務：[${selectedNames}] 聯合渲染。`);
    await generateProcess(allTargetIndices);
    setLoading(prev => ({ ...prev, isGenerating: false }));
    if (!stopGenerationRef.current) addLog("選定任務完成。");
  };

  // 切換類別選取狀態
  const toggleCategory = (type: ImageCategory) => {
    setSelectedCategories(prev => 
      prev.includes(type) 
        ? prev.filter(t => t !== type) 
        : [...prev, type]
    );
  };

  const handleSaveToGallery = () => {
    const validImages = currentGeneration.filter((img): img is string => img !== null);
    if (validImages.length === 0) return;

    const newMockup: GeneratedMockup = {
      id: Math.random().toString(36).substr(2, 9),
      imageUrl: validImages[0],
      allImages: validImages,
      prompt: productTitle || "Pro 系列設計稿",
      createdAt: Date.now()
    };

    setGallery(prev => [newMockup, ...prev]);
    addLog("存檔完成。");
    setView('gallery');
  };

  if (showIntro) return <IntroSequence onComplete={() => setShowIntro(false)} />;

  return (
    <div className="min-h-screen bg-[#fdfdfd] text-[#333333] font-sans flex flex-col md:flex-row overflow-hidden">
      {showApiKeyDialog && <ApiKeyDialog onContinue={handleApiKeyDialogContinue} />}

      <aside className="w-64 border-r border-[#eeeeee] bg-white hidden md:flex flex-col flex-shrink-0">
        <div className="h-20 border-b border-[#eeeeee] flex items-center px-8">
          <div className="flex items-center gap-3">
            <Package size={20} className="text-[#7f0019]" />
            <span className="font-light text-xl tracking-[0.2em]">MURO AI</span>
          </div>
        </div>

        <nav className="p-6 flex-1 space-y-2">
          <button onClick={() => setView('generate')} className={`w-full flex items-center gap-4 px-4 py-3 rounded-sm transition-colors ${view === 'generate' ? 'bg-[#f5f5f5] text-[#333333] font-medium' : 'text-[#999999] hover:bg-[#fafafa]'}`}>
            <Wand2 size={18} strokeWidth={1.5} />
            <span className="text-sm tracking-widest uppercase">設計工作台</span>
          </button>
          <button onClick={() => setView('gallery')} className={`w-full flex items-center gap-4 px-4 py-3 rounded-sm transition-colors ${view === 'gallery' ? 'bg-[#f5f5f5] text-[#333333] font-medium' : 'text-[#999999] hover:bg-[#fafafa]'}`}>
            <History size={18} strokeWidth={1.5} />
            <span className="text-sm tracking-widest uppercase">作品集</span>
          </button>
        </nav>

        <div className="p-6 border-t border-[#eeeeee] bg-zinc-50 space-y-4">
          <div className="flex items-center gap-2 text-[10px] text-amber-600 uppercase tracking-widest font-bold">
            <Crown size={12} className="text-amber-500" />
            <span>800px JPG Mode</span>
          </div>
          <div className="flex items-center gap-2 text-[10px] text-zinc-400 uppercase tracking-widest">
            <Trophy size={12} className="text-zinc-300" />
            <span>Standard Output</span>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto bg-[#fafafa]">
        <div className="max-w-6xl mx-auto px-6 py-12 md:py-16">
          {view === 'generate' && (
            <div className="animate-fade-in space-y-12">
              <header className="flex items-end justify-between">
                <div className="space-y-2">
                  <h2 className="text-3xl font-light text-zinc-800 tracking-wider">設計工作台</h2>
                  <div className="flex items-center gap-4">
                    <p className="text-zinc-400 text-sm italic">Pro 800px JPG 系列：多選類別同步生產。</p>
                  </div>
                </div>
                <div className="hidden lg:block w-80 bg-white border border-zinc-100 p-5 rounded-sm shadow-sm">
                  <div className="flex items-center gap-2 mb-3 pb-2 border-b border-zinc-50">
                    <Zap size={14} className="text-amber-500 fill-amber-500" />
                    <span className="text-[10px] uppercase tracking-widest text-zinc-500 font-bold">渲染狀態</span>
                  </div>
                  <div className="space-y-2.5 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
                    {optLogs.map((log, i) => (
                      <div key={i} className={`flex gap-2 text-[10px] ${i === 0 ? 'text-zinc-800 font-medium' : 'text-zinc-300'}`}>
                        <ChevronRight size={10} className="flex-shrink-0 mt-0.5 opacity-50" />
                        <p className="leading-relaxed">{log}</p>
                      </div>
                    ))}
                  </div>
                </div>
              </header>

              <div className="muji-panel p-8 md:p-12 space-y-12 shadow-sm">
                <div className="grid grid-cols-1 lg:grid-cols-4 gap-12">
                  <div className="lg:col-span-1 space-y-10">
                    <FileUploader 
                      label="產品主圖素材 (基本外觀)" 
                      onFilesSelect={handleMainFilesSelect} 
                      previews={mainUploadedPreviews} 
                      onRemove={idx => setMainUploadedPreviews(p => p.filter((_, i) => i !== idx))} 
                      onClearAll={() => setMainUploadedPreviews([])} 
                    />

                    <FileUploader 
                      label="詳情細節素材 (細節、功能、標籤)" 
                      onFilesSelect={handleDetailFilesSelect} 
                      previews={detailUploadedPreviews} 
                      onRemove={idx => setDetailUploadedPreviews(p => p.filter((_, i) => i !== idx))} 
                      onClearAll={() => setDetailUploadedPreviews([])} 
                    />
                  </div>

                  <div className="lg:col-span-3 flex flex-col space-y-8">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="space-y-1">
                        <label className="text-[10px] uppercase tracking-[0.2em] text-zinc-400">產品名稱</label>
                        <input type="text" value={productTitle} onChange={e => setProductTitle(e.target.value)} placeholder="如：日系極簡加濕器" className="w-full text-lg py-2 border-b border-zinc-200 bg-transparent focus:outline-none focus:border-zinc-800 transition-colors" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[10px] uppercase tracking-[0.2em] text-zinc-400 flex items-center gap-2"><Type size={12} /> 封面標題</label>
                        <input type="text" value={mainImageTitle} onChange={e => setMainImageTitle(e.target.value)} placeholder="顯示於主圖的核心文字" className="w-full text-lg py-2 border-b border-zinc-200 bg-transparent focus:outline-none focus:border-zinc-800 transition-colors" />
                      </div>
                    </div>

                    <div className="space-y-4">
                      <div className="flex items-center justify-between border-b border-zinc-100 pb-2">
                        <label className="text-[10px] uppercase tracking-[0.2em] text-zinc-400 flex items-center gap-2">
                          <List size={12} /> 產品規格參數
                        </label>
                        <button onClick={handleAddSpec} className="text-[10px] text-zinc-500 hover:text-zinc-800 flex items-center gap-1">
                          <Plus size={12} /> 新增
                        </button>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-4 bg-zinc-50/50 p-6 rounded-sm border border-zinc-100">
                        {specs.map((spec, index) => (
                          <div key={index} className="flex items-center gap-3 group">
                            <input 
                              type="text" 
                              value={spec.key} 
                              onChange={(e) => handleUpdateSpec(index, 'key', e.target.value)}
                              placeholder="屬性"
                              className="w-24 text-[11px] py-1.5 border-b border-zinc-200 bg-transparent focus:border-zinc-800 outline-none font-medium text-zinc-500 uppercase tracking-widest" 
                            />
                            <input 
                              type="text" 
                              value={spec.value} 
                              onChange={(e) => handleUpdateSpec(index, 'value', e.target.value)}
                              placeholder="數值"
                              className="flex-1 text-[11px] py-1.5 border-b border-zinc-200 bg-transparent focus:border-zinc-800 outline-none text-zinc-800" 
                            />
                            <button onClick={() => handleRemoveSpec(index)} className="opacity-0 group-hover:opacity-100 text-zinc-300 hover:text-red-800 transition-all p-1">
                              <Trash2 size={12} />
                            </button>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="space-y-1">
                      <label className="text-[10px] uppercase tracking-[0.2em] text-zinc-400 flex items-center gap-2">
                        <Fingerprint size={12} /> Pro 優化指令
                      </label>
                      <textarea 
                        value={optimizationPrompt} 
                        onChange={e => setOptimizationPrompt(e.target.value)} 
                        placeholder="例如：強調磨砂質感、暖白色與原木質地" 
                        className="w-full text-sm py-2 border-b border-zinc-200 bg-transparent focus:outline-none focus:border-zinc-800 transition-colors resize-none h-16"
                      />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="space-y-1">
                        <label className="text-[10px] uppercase tracking-[0.2em] text-zinc-400 flex items-center gap-2"><MapPin size={12} /> 情境描述</label>
                        <input type="text" value={sceneDescription} onChange={e => setSceneDescription(e.target.value)} placeholder="如：溫潤木質調空間" className="w-full text-xs py-2 border-b border-zinc-200 bg-transparent focus:outline-none focus:border-zinc-800 transition-colors" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[10px] uppercase tracking-[0.2em] text-zinc-400 flex items-center gap-2 flex-wrap">
                          <CheckCircle2 size={12} /> 本品優勢 <span className="text-zinc-300 text-[8px]">(內容將完整傳送)</span>
                        </label>
                        <input type="text" value={ownAdvantage} onChange={(e) => setOwnAdvantage(e.target.value)} placeholder="如：細緻噴霧、親膚質感" className="w-full text-xs py-2 border-b border-zinc-200 bg-transparent focus:outline-none focus:border-zinc-800 transition-colors" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[10px] uppercase tracking-[0.2em] text-zinc-400 flex items-center gap-2 flex-wrap">
                          <AlertCircle size={12} /> 市場劣勢 <span className="text-zinc-300 text-[8px]">(內容將完整傳送)</span>
                        </label>
                        <input type="text" value={marketDisadvantage} onChange={e => setMarketDisadvantage(e.target.value)} placeholder="如：水珠過大、塑料感重" className="w-full text-xs py-2 border-b border-zinc-200 bg-transparent focus:outline-none focus:border-zinc-800 transition-colors" />
                      </div>
                    </div>

                    <div className="space-y-4 pt-4">
                      {/* 下方為類別多選區 */}
                      <div className="space-y-2">
                        <div className="flex items-center justify-between">
                          <label className="text-[10px] uppercase tracking-[0.2em] text-zinc-400 flex items-center gap-2">
                            <LayoutGrid size={12} /> 1. 勾選欲生成類型
                          </label>
                          <div className="flex gap-2">
                            <button onClick={() => setSelectedCategories(['main', 'comparison', 'lifestyle', 'detail'])} className="text-[9px] text-zinc-400 hover:text-zinc-800 uppercase tracking-widest">全選</button>
                            <button onClick={() => setSelectedCategories([])} className="text-[9px] text-zinc-400 hover:text-zinc-800 uppercase tracking-widest">重設</button>
                          </div>
                        </div>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                          {categoryConfigs.map(config => {
                            const isSelected = selectedCategories.includes(config.type);
                            return (
                              <button 
                                key={config.type} 
                                onClick={() => toggleCategory(config.type)}
                                className={`relative py-4 px-2 border rounded-sm flex flex-col items-center gap-2 transition-all duration-300 group ${isSelected ? 'border-zinc-800 bg-zinc-50 ring-1 ring-zinc-800' : 'border-zinc-100 hover:border-zinc-300 bg-white'}`}
                              >
                                <div className={`transition-colors ${isSelected ? 'text-zinc-800' : 'text-zinc-300 group-hover:text-zinc-400'}`}>
                                  {config.icon}
                                </div>
                                <span className={`text-[10px] tracking-widest font-medium uppercase transition-colors ${isSelected ? 'text-zinc-800' : 'text-zinc-400'}`}>
                                  {config.name}
                                </span>
                                {isSelected && (
                                  <div className="absolute top-1 right-1">
                                    <Check size={10} className="text-zinc-800" />
                                  </div>
                                )}
                              </button>
                            );
                          })}
                        </div>
                      </div>

                      <div className="flex gap-4 pt-4">
                        {!loading.isGenerating ? (
                          <Button 
                            onClick={handleStartProduction} 
                            disabled={(!productTitle.trim() && mainUploadedPreviews.length === 0) || selectedCategories.length === 0} 
                            className="flex-1 py-6 text-lg tracking-[0.3em] font-light muji-button-primary shadow-sm" 
                            icon={<Crown size={20} />}
                          >
                            2. 開始製作
                          </Button>
                        ) : (
                          <Button onClick={() => { stopGenerationRef.current = true; setLoading({isGenerating: false, message: '已中斷'}); }} variant="secondary" className="flex-1 py-6 text-red-800 border-red-800" icon={<Square size={20} fill="currentColor" />}>停止渲染</Button>
                        )}
                        <Button 
                          onClick={handleReset} 
                          variant="outline" 
                          className="px-8 py-6 text-zinc-400 hover:text-red-800 hover:border-red-800"
                          icon={<RotateCcw size={20} />}
                        >
                          全部清除
                        </Button>
                      </div>

                      {loading.message && (
                        <div className="flex items-center gap-3 px-5 py-3 bg-zinc-50 border border-zinc-100 animate-fade-in rounded-sm">
                          {loading.isGenerating ? <RefreshCw size={16} className="text-zinc-400 animate-spin" /> : <AlertCircle size={16} className="text-red-800" />}
                          <span className={`text-[10px] uppercase tracking-widest ${loading.isGenerating ? 'text-zinc-400' : 'text-red-800 font-medium'}`}>{loading.message}</span>
                        </div>
                      )}

                      {currentGeneration.some(Boolean) && !loading.isGenerating && (
                        <Button onClick={handleSaveToGallery} variant="secondary" className="w-full py-4 border-zinc-800 shadow-sm uppercase tracking-widest" icon={<CheckCircle2 size={18} />}>存入作品集</Button>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              {displayFilter && (
                <div className="space-y-20 animate-fade-in pt-12 border-t border-zinc-100">
                  {categoryConfigs.filter(c => displayFilter === 'all' || selectedCategories.includes(c.type)).map(section => (
                    <div key={section.type} className="space-y-12">
                      <div className="flex items-center justify-between border-b border-zinc-100 pb-3">
                        <div className="flex items-center gap-3">
                          <p className="text-[11px] text-zinc-600 uppercase tracking-[0.2em] font-medium flex items-center gap-3">{section.icon} {section.name}</p>
                          <span className="text-[9px] bg-zinc-800 text-white px-2 py-0.5 rounded-sm tracking-widest font-bold border border-zinc-800 uppercase">
                            800px JPG
                          </span>
                        </div>
                        <button onClick={() => {
                          if (!selectedCategories.includes(section.type)) setSelectedCategories(prev => [...prev, section.type]);
                          handleStartProduction();
                        }} disabled={loading.isGenerating} className="text-[10px] text-zinc-400 hover:text-zinc-800 uppercase tracking-widest disabled:opacity-20 flex items-center gap-2 transition-colors">
                          <RefreshCw size={12} className={activeIndices.some(idx => section.indices.includes(idx)) ? "animate-spin" : ""} /> 重新生成
                        </button>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                        {section.indices.map(i => (
                          <div key={i} onClick={() => currentGeneration[i] && setZoomedImage({url: currentGeneration[i]!, title: `${section.name} ${i % 3 + 1}`})} className={`aspect-square bg-white border border-zinc-100 flex items-center justify-center overflow-hidden transition-all duration-500 shadow-sm ${currentGeneration[i] ? 'cursor-zoom-in hover:shadow-md' : 'bg-zinc-50/20'}`}>
                            {currentGeneration[i] ? (
                              <img src={currentGeneration[i]!} className="w-full h-full object-cover animate-fade-in" alt={section.name} />
                            ) : (
                              <div className="relative w-full h-full flex flex-col items-center justify-center gap-2">
                                {activeIndices.includes(i) && <div className="absolute inset-0 animate-pulse bg-zinc-100/40" />}
                                <span className={`text-[9px] uppercase tracking-widest ${activeIndices.includes(i) ? 'text-zinc-500' : 'text-zinc-200'}`}>
                                  {activeIndices.includes(i) ? '渲染中...' : '等待中'}
                                </span>
                              </div>
                            )}
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {view === 'gallery' && (
            <div className="animate-fade-in space-y-12">
              <header className="text-center">
                <h2 className="text-3xl font-light tracking-wider uppercase">設計作品集</h2>
                <p className="text-xs text-zinc-400 mt-2 tracking-widest uppercase font-light">Pro Quality Design Collection</p>
              </header>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {gallery.map(item => (
                  <div key={item.id} className="muji-panel bg-white shadow-sm overflow-hidden group border-zinc-200">
                    <img src={item.imageUrl} className="w-full aspect-[4/3] object-cover cursor-pointer hover:scale-105 transition-transform duration-700" onClick={() => setSelectedMockup(item)} alt={item.prompt} />
                    <div className="p-5 border-t border-zinc-50 flex justify-between items-center bg-white">
                      <div className="flex items-center gap-3">
                        <Crown size={12} className="text-amber-500" />
                        <span className="text-xs text-zinc-600 tracking-widest font-medium">{item.prompt}</span>
                      </div>
                      <span className="text-[10px] text-zinc-300 uppercase tracking-widest">{new Date(item.createdAt).toLocaleDateString()}</span>
                    </div>
                  </div>
                ))}
              </div>
              {gallery.length === 0 && <div className="py-20 text-center text-zinc-300 font-light tracking-widest uppercase">尚未有儲存的作品。</div>}
              <div className="flex justify-center"><Button onClick={() => setView('generate')} variant="secondary" className="px-12 uppercase tracking-[0.3em]">返回工作台</Button></div>
            </div>
          )}
        </div>
      </main>

      {zoomedImage && (
        <div className="fixed inset-0 z-[120] bg-black/95 backdrop-blur-md flex flex-col items-center justify-center p-4 md:p-12 animate-fade-in">
          <div className="absolute top-6 right-6 flex items-center gap-4 z-[130]">
            <button 
              onClick={() => downloadImage(zoomedImage.url, `${productTitle}-${zoomedImage.title}`)}
              className="flex items-center gap-2 px-6 py-2.5 bg-white text-black hover:bg-zinc-100 rounded-full transition-all text-xs tracking-widest font-medium shadow-xl"
            >
              <Download size={16} /> 下載 JPG
            </button>
            <button 
              onClick={() => setZoomedImage(null)}
              className="p-2.5 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all border border-white/20 shadow-xl"
            >
              <X size={20} />
            </button>
          </div>

          <img 
            src={zoomedImage.url} 
            className="max-h-[80vh] max-w-full object-contain shadow-2xl animate-fade-in border border-white/10" 
            alt={zoomedImage.title}
          />

          <div className="mt-8 text-center space-y-2">
            <h4 className="text-white font-light tracking-[0.3em] text-lg uppercase">{productTitle}</h4>
            <p className="text-white/40 text-[10px] tracking-[0.4em] uppercase">{zoomedImage.title} • MURO 800px Optimized</p>
          </div>
        </div>
      )}

      {selectedMockup && (
        <div className="fixed inset-0 z-[100] bg-white overflow-y-auto p-8 md:p-20" onClick={() => setSelectedMockup(null)}>
           <div className="max-w-5xl mx-auto space-y-16" onClick={e => e.stopPropagation()}>
             <div className="flex flex-col items-center gap-4 border-b border-zinc-100 pb-10">
               <Package size={32} className="text-[#7f0019]" />
               <h3 className="text-2xl text-center font-light tracking-[0.6em] text-zinc-800">{selectedMockup.prompt}</h3>
               <p className="text-[10px] text-zinc-400 uppercase tracking-[0.4em]">MURO Studio Presentation Set</p>
             </div>
             <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
               {selectedMockup.allImages?.map((img, i) => (
                 <div key={i} className="relative group border border-zinc-100 overflow-hidden shadow-sm aspect-square bg-zinc-50">
                    <img src={img} className="w-full h-full object-cover" alt={`${selectedMockup.prompt} ${i}`} />
                    <button 
                      onClick={() => downloadImage(img, `${selectedMockup.prompt}-set-${i+1}`)}
                      className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center text-white gap-2"
                    >
                      <Download size={24} />
                      <span className="text-[10px] tracking-widest uppercase">下載 JPG</span>
                    </button>
                 </div>
               ))}
             </div>
             <div className="text-center pt-8"><Button variant="secondary" onClick={() => setSelectedMockup(null)} className="px-12 uppercase tracking-widest">關閉預覽</Button></div>
           </div>
        </div>
      )}
    </div>
  );
}
